// Fixed Resume Search Config - Correct form field names
const formData = $input.first().json;

// Debug: Log the actual form data to see field names
console.log('Form Data Received:', JSON.stringify(formData, null, 2));

// Extract form parameters using CORRECT field names from your form
const jobTitle = formData["Job Title"] || formData.job_title || 'Software Engineer';
const jobDescription = formData["Job Description"] || formData.job_description || '';
const requiredSkills = formData["Required Skills"] || formData.required_skills || '';
const optionalSkills = formData["Optional Skills"] || formData.optional_skills || ''; // ✅ ADD THIS LINE

// Handle Experience array (your form returns an array)
let experienceLevel = '2-3 years';
if (formData["Experience"] && Array.isArray(formData["Experience"])) {
  experienceLevel = formData["Experience"][0] || '2-3 years';
} else if (formData.experience) {
  experienceLevel = formData.experience;
}

const salaryBudget = formData["Salary Budget (LPA)"] || formData.salary_budget || '10-15 LPA';
const requestedCount = parseInt(formData["Number of Candidates"]) || parseInt(formData.number_of_candidates) || 10;

// Debug: Log extracted values
console.log('Extracted Values:', {
  jobTitle,
  jobDescription, 
  requiredSkills,
  optionalSkills, // ✅ ADD THIS LINE
  experienceLevel,
  salaryBudget,
  requestedCount
});

// Simple approach: Get ALL resumes, let AI do the filtering
return [{
  json: {
    searchQuery: "pdf", // Simple search to get all PDF files
    folderName: "Candidate Resume",
    jobRequirements: {
      title: jobTitle,
      description: jobDescription,
      requiredSkills: requiredSkills,
      optionalSkills: optionalSkills, // ✅ ADD THIS LINE
      experienceLevel: experienceLevel,
      salaryBudget: salaryBudget,
      requestedCount: requestedCount
    },
    searchMetadata: {
      generatedAt: new Date().toISOString(),
      searchType: "get_all_resumes"
    },
    // Debug info
    originalFormData: formData,
    extractedFields: {
      jobTitle,
      jobDescription,
      requiredSkills,
      optionalSkills, // ✅ ADD THIS LINE
      experienceLevel,
      salaryBudget,
      requestedCount
    },
    summary: `Getting all resumes to find top ${requestedCount} ${jobTitle} candidates with ${experienceLevel} experience`
  }
}];

// FIXED: AI Resume Matcher - V15 with Proper Candidate Limiting
// This node ensures the AI respects the requested candidate count

const resumeData = $input.all();

// Get job requirements from earlier in the workflow
let jobRequirements = {};
try {
  const searchConfig = $('Resume Search Config').first().json;
  jobRequirements = searchConfig.jobRequirements || {};
} catch (error) {
  console.log('Could not get job requirements, using defaults');
  jobRequirements = {
    title: 'Software Engineer',
    requiredSkills: 'Programming',
    optionalSkills: '',
    experienceLevel: '2-5 years',
    requestedCount: 5
  };
}

const requestedCount = jobRequirements.requestedCount || 5;
console.log(`🎯 REQUESTED CANDIDATE COUNT: ${requestedCount}`);
console.log(`📄 TOTAL RESUMES FOUND: ${resumeData.length}`);

// Prepare resume texts
const candidateTexts = resumeData.map((item, index) => ({
  candidateId: index + 1,
  resumeText: item.json.text || '',
  extractedTextLength: item.json.text?.length || 0
}));

// ✅ FIXED: Enhanced prompt with stronger candidate limiting instructions
const createDynamicPrompt = (jobReqs, candidates) => {
  return `You are an expert HR recruiter and resume analyst.

**CRITICAL INSTRUCTION: You MUST return EXACTLY ${jobReqs.requestedCount} candidates, no more, no less.**

Analyze these ${candidates.length} candidate resumes against the job requirements and provide structured candidate data for the TOP ${jobReqs.requestedCount} BEST MATCHES ONLY.

**DYNAMIC JOB REQUIREMENTS:**
- **Position:** ${jobReqs.title}
- **Required Skills:** ${jobReqs.requiredSkills}
- **Optional Skills:** ${jobReqs.optionalSkills || 'None specified'}
- **Experience Level:** ${jobReqs.experienceLevel}
- **Salary Budget:** ${jobReqs.salaryBudget || 'Not specified'}
- **EXACT NUMBER OF CANDIDATES NEEDED:** ${jobReqs.requestedCount} (MANDATORY LIMIT)
- **Job Description:** ${jobReqs.description || 'Standard role requirements'}

**CANDIDATE RESUMES TO ANALYZE:**
${candidates.map(c => `
**CANDIDATE ${c.candidateId}:**
${c.resumeText}
---
`).join('\n')}

**ANALYSIS INSTRUCTIONS:**

For EACH candidate, extract and analyze the following information based on the specific job requirements above:

1. **Basic Information:**
   - Full name (clean, properly formatted)
   - Email address
   - Phone number
   - Current location/city

2. **Professional Background:**
   - Current job title
   - Current company
   - Years of total experience
   - Career progression and roles

3. **Skills Analysis:**
   - Technical skills (programming languages, tools, frameworks)
   - How well skills match "${jobReqs.requiredSkills}" specifically (REQUIRED - HIGH PRIORITY)
   - How many optional skills from "${jobReqs.optionalSkills || 'none'}" they possess (BONUS POINTS)
   - Domain expertise relevant to "${jobReqs.title}"
   - Soft skills and certifications

4. **Experience Assessment:**
   - Does experience level match "${jobReqs.experienceLevel}"?
   - Relevant project experience for "${jobReqs.title}" role
   - Industry experience
   - Leadership/team experience

5. **Match Score (1-100):**
   - Overall fit for the "${jobReqs.title}" role
   - Heavy weight on "${jobReqs.requiredSkills}" match (70% of score)
   - Bonus points for matching "${jobReqs.optionalSkills || 'none'}" (15% of score)
   - Experience level, project quality, career trajectory (15% of score)
   - Provide detailed reasoning for the score

6. **Salary & Fit Analysis:**
   - Salary expectation estimate
   - How it compares to "${jobReqs.salaryBudget || 'budget'}"
   - Cultural fit indicators
   - Availability assessment

**CRITICAL OUTPUT REQUIREMENTS:**

1. **ANALYZE ALL ${candidates.length} CANDIDATES** but **RETURN ONLY THE TOP ${jobReqs.requestedCount} HIGHEST SCORING ONES**
2. **RANK ALL CANDIDATES** by match score (highest to lowest)
3. **SELECT ONLY THE TOP ${jobReqs.requestedCount}** candidates for the final JSON output
4. **ENSURE EXACTLY ${jobReqs.requestedCount} CANDIDATES** in the final response

**OUTPUT FORMAT:**
Return a JSON array with EXACTLY ${jobReqs.requestedCount} candidate objects (the highest scoring ones). Each object must have this structure:

[
  {
    "name": "Full Name",
    "email": "email@example.com", 
    "phone": "+91-XXXXXXXXXX",
    "location": "City, State",
    "current_company": "Company Name",
    "job_title": "Current Job Title",
    "experience_years": 4,
    "skills": ["skill1", "skill2", "skill3", "..."],
    "salary_expectation": "XX-XX LPA",
    "profile_url": "https://linkedin.com/in/name",
    "portfolio_url": "https://portfolio.com",
    "resume_url": "https://drive.google.com/resume.pdf",
    "bio": "Brief professional summary",
    "availability": "Available in X days",
    "platform_metrics": {
      "profile_completeness": 85,
      "endorsements": 10
    },
    "source": "Resume Database",
    "match_score": 85,
    "scraped_at": "${new Date().toISOString()}",
    "form_job_title": "${jobReqs.title}",
    "form_required_skills": "${jobReqs.requiredSkills}",
    "form_optional_skills": "${jobReqs.optionalSkills || 'None'}",
    "form_experience": "${jobReqs.experienceLevel}",
    "form_salary_budget": "${jobReqs.salaryBudget}",
    "ai_analysis": {
      "key_strengths": ["strength1", "strength2", "strength3"],
      "concerns": ["concern1", "concern2"],
      "skill_match_percentage": 85,
      "optional_skills_matched": ["optional_skill1", "optional_skill2"],
      "optional_skills_count": 2,
      "experience_fit": "Excellent/Good/Average/Poor",
      "recommended_action": "Strong hire/Interview/Consider/Pass",
      "reasoning": "Detailed explanation of match score based on ${jobReqs.title} requirements including required and optional skills analysis"
    },
    "extracted_text_length": ${candidates[0]?.extractedTextLength || 0},
    "raw_resume_text": "Full resume text for reference"
  }
]

**MANDATORY SELECTION PROCESS:**
1. Score ALL ${candidates.length} candidates (1-100 scale)
2. Rank them by score (highest first)
3. Take ONLY the top ${jobReqs.requestedCount} candidates
4. Return EXACTLY ${jobReqs.requestedCount} candidates in the JSON array

**IMPORTANT DYNAMIC MATCHING RULES:**
- Focus heavily on "${jobReqs.requiredSkills}" when scoring (PRIMARY CRITERIA)
- Give bonus points for matching "${jobReqs.optionalSkills || 'none'}" (SECONDARY CRITERIA)
- Adjust experience expectations based on "${jobReqs.experienceLevel}"
- Consider salary expectations vs "${jobReqs.salaryBudget || 'the budget'}"
- Provide realistic, varied match scores (don't make them all the same)
- Be thorough in skills extraction for "${jobReqs.title}" role specifically
- Consider career progression and project quality, not just years
- Clearly differentiate between required skills (must-have) and optional skills (nice-to-have)

**FINAL REMINDER: Return EXACTLY ${jobReqs.requestedCount} candidates (the top scoring ones) in the JSON array. This is mandatory and non-negotiable.**`;
};

// Generate dynamic prompt
const dynamicPrompt = createDynamicPrompt(jobRequirements, candidateTexts);

console.log(`✅ PROMPT GENERATED for ${candidateTexts.length} resumes, requesting TOP ${requestedCount} candidates`);

return [{
  json: {
    aiPrompt: dynamicPrompt,
    candidateCount: candidateTexts.length,
    requestedCandidateCount: requestedCount, // ✅ ADDED: Track requested count
    jobRequirements: jobRequirements,
    resumeTexts: candidateTexts,
    instruction: `This data is ready for AI Agent analysis. AI will process ${candidateTexts.length} resumes but return only the TOP ${requestedCount} candidates as specified.`,
    preparedAt: new Date().toISOString(),
    dynamicFields: {
      position: jobRequirements.title,
      skills: jobRequirements.requiredSkills,
      optionalSkills: jobRequirements.optionalSkills,
      experience: jobRequirements.experienceLevel,
      budget: jobRequirements.salaryBudget,
      count: requestedCount, // ✅ FIXED: Use proper variable
      totalResumes: candidateTexts.length
    }
  }
}];

// FIXED: Extract candidates from AI Agent response with COUNT VALIDATION
const aiResponse = $input.first().json;

console.log('AI Response structure:', JSON.stringify(aiResponse, null, 2));

// Get the requested count from earlier node
let requestedCount = 5;
try {
  const searchConfig = $('Resume Search Config').first().json;
  requestedCount = searchConfig.jobRequirements?.requestedCount || 5;
  console.log(`🎯 EXPECTED CANDIDATE COUNT: ${requestedCount}`);
} catch (error) {
  console.log('Could not get requested count, using default: 5');
}

// Handle different possible response structures
let candidatesText;

// Check if it's already the parsed output (structured output parser)
if (Array.isArray(aiResponse)) {
  // Already an array of candidates
  const candidates = aiResponse.slice(0, requestedCount); // ✅ ENSURE LIMIT
  console.log(`✅ Direct array response: ${aiResponse.length} found, limiting to ${requestedCount}`);
  return candidates.map(candidate => ({ json: candidate }));
}

// Check if it's in the 'output' field (structured output parser format)
if (aiResponse.output && Array.isArray(aiResponse.output)) {
  const candidates = aiResponse.output.slice(0, requestedCount); // ✅ ENSURE LIMIT
  console.log(`✅ Output array response: ${aiResponse.output.length} found, limiting to ${requestedCount}`);
  return candidates.map(candidate => ({ json: candidate }));
}

// Check if it's in the 'response.generations' format (raw LLM response)
if (aiResponse.response && aiResponse.response.generations) {
  candidatesText = aiResponse.response.generations[0][0].text;
} 
// Check if it's directly in 'output' as text
else if (aiResponse.output && typeof aiResponse.output === 'string') {
  candidatesText = aiResponse.output;
}
// Check if it's directly in 'text' field
else if (aiResponse.text) {
  candidatesText = aiResponse.text;
}
// Check if the whole response is the text
else if (typeof aiResponse === 'string') {
  candidatesText = aiResponse;
}
else {
  // Log the structure to help debug
  console.log('Unexpected response structure:', Object.keys(aiResponse));
  throw new Error('Could not find candidates data in AI response');
}

// FIXED: Clean the candidatesText to remove markdown code blocks
if (candidatesText) {
  console.log('Raw candidates text (first 200 chars):', candidatesText.substring(0, 200));
  // Remove markdown code blocks if present
  candidatesText = candidatesText.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();
  // Also handle cases where there might be extra text before/after JSON
  // Find the JSON array by looking for the first [ and last ]
  const startIndex = candidatesText.indexOf('[');
  const endIndex = candidatesText.lastIndexOf(']');
  if (startIndex !== -1 && endIndex !== -1 && endIndex > startIndex) {
    candidatesText = candidatesText.substring(startIndex, endIndex + 1);
  }
  console.log('Cleaned candidates text (first 200 chars):', candidatesText.substring(0, 200));
}

// Parse the JSON string to get the actual candidate array
try {
  if (!candidatesText) {
    throw new Error('No candidates text found to parse');
  }
  let candidates = JSON.parse(candidatesText);
  // Ensure it's an array
  if (!Array.isArray(candidates)) {
    console.log('Parsed data type:', typeof candidates);
    console.log('Parsed data:', candidates);
    throw new Error('Parsed data is not an array');
  }
  console.log(`📊 AI RETURNED: ${candidates.length} candidates`);
  // ✅ CRITICAL FIX: Ensure we don't exceed requested count
  if (candidates.length > requestedCount) {
    console.log(`⚠️ AI returned ${candidates.length} candidates, but only ${requestedCount} were requested. Limiting to top ${requestedCount}.`);
    // Sort by match_score if available, then take top N
    candidates.sort((a, b) => (b.match_score || 0) - (a.match_score || 0));
    candidates = candidates.slice(0, requestedCount);
  }
  console.log(`✅ FINAL RESULT: ${candidates.length} candidates (requested: ${requestedCount})`);
  // Return in n8n format
  return candidates.map(candidate => ({ json: candidate }));
} catch (parseError) {
  console.log('Parse error:', parseError.message);
  console.log('Raw text length:', candidatesText?.length);
  console.log('Candidates text (first 500 chars):', candidatesText?.substring(0, 500));
  console.log('Candidates text (last 100 chars):', candidatesText?.substring(-100));
  // Try to provide more helpful error information
  if (candidatesText?.includes('```')) {
    throw new Error(`Failed to parse candidates JSON: Found markdown code blocks. Text starts with: ${candidatesText.substring(0, 100)}`);
  } else {
    throw new Error(`Failed to parse candidates JSON: ${parseError.message}. Text starts with: ${candidatesText?.substring(0, 100)}`);
  }
}

// Process HR Selections & Generate MCQ Questions - UPDATED WITH SURVEY QUESTIONS AND EXPECTED ANSWERS
// This node extracts HR selections and prepares data for AI MCQ generation

const hrFormData = $input.first().json;

// Extract survey questions from earlier in the workflow
let surveyQuestions = [];
try {
  const surveyData = $('Process Survey Questions').first().json;
  surveyQuestions = surveyData.surveyQuestions || [];
  console.log(`✅ Retrieved ${surveyQuestions.length} survey questions from earlier node`);
  if (surveyQuestions.length > 0) {
    console.log('Survey questions found:', surveyQuestions.map(q => q.fieldLabel));
    console.log('Qualifying questions:', surveyQuestions.filter(q => q.isQualifying).map(q => `${q.fieldLabel} (expects: ${q.expectedAnswer})`));
  }
} catch (error) {
  console.log('No survey questions found, continuing without survey data');
  surveyQuestions = [];
}

// Get candidate data from earlier in workflow
let candidateData = {};
let jobRequirements = {};

try {
  const reviewData = $('Prepare HR Review Data').first().json;
  candidateData = reviewData;
  jobRequirements = reviewData.jobRequirements || {};
} catch (error) {
  console.log('Could not get candidate data, using defaults');
  jobRequirements = {
    title: 'Software Engineer',
    requiredSkills: 'Programming',
    optionalSkills: '',
    experienceLevel: '2-5 years'
  };
}

// Extract HR form selections
const selectedCandidateLabels = hrFormData['Select Candidates for Round 0 AI Screening'] || hrFormData.selected_candidates || [];
const focusAreas = hrFormData['Assessment Focus Areas'] || hrFormData.focus_areas || ['Comprehensive Assessment (All Areas)'];
const assessmentType = hrFormData['Assessment Configuration'] || hrFormData.assessment_type || ['Standard MCQ Assessment (20 questions)'];

console.log('HR Form Data:', JSON.stringify(hrFormData, null, 2));
console.log('Selected Candidates:', selectedCandidateLabels);
console.log('Focus Areas:', focusAreas);
console.log('Assessment Type:', assessmentType);
console.log(`Survey Questions to include: ${surveyQuestions.length}`);

// Process selected candidates
const allCandidates = candidateData.candidates || [];
const selectedCandidates = [];

selectedCandidateLabels.forEach(selectedLabel => {
  const candidate = allCandidates.find(c => c.selectionLabel === selectedLabel);
  if (candidate) {
    selectedCandidates.push({
      id: candidate.id,
      name: candidate.name,
      email: candidate.email,
      phone: candidate.phone,
      location: candidate.location,
      currentCompany: candidate.currentCompany,
      jobTitle: candidate.jobTitle,
      experienceYears: candidate.experienceYears,
      skills: candidate.skills,
      matchScore: candidate.matchScore,
      aiAnalysis: candidate.aiAnalysis,
      bio: candidate.bio,
      availability: candidate.availability,

      // Generate unique screening identifier
      screeningId: `screening_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,

      // Create expiration date (3 days from now)
      linkExpiration: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString(),

      // Assessment status
      assessmentStatus: 'invited',
      invitedAt: new Date().toISOString()
    });
  }
});

console.log(`Processed ${selectedCandidates.length} selected candidates`);

// Question Pool Configuration
const questionsPerCandidate = 3;
const questionPoolSize = 5;

// Determine if coding questions should be included
const includeCoding = assessmentType.some(type => type.includes('coding challenge'));
const focusOnTechStack = assessmentType.some(type => type.includes('technology stack'));

// Generate comprehensive MCQ prompt for QUESTION POOL
const generateMCQPrompt = () => {
  const jobTitle = jobRequirements.title || 'Software Engineer';
  const jobDescription = jobRequirements.description || 'Standard software engineering role';
  const requiredSkills = jobRequirements.requiredSkills || 'Programming skills';
  const optionalSkills = jobRequirements.optionalSkills || 'None specified';
  const experienceLevel = jobRequirements.experienceLevel || '2-5 years';

  return `You are an expert Technical Assessment Designer. Create ${questionPoolSize} multiple-choice questions for a Round 0 AI Screening assessment QUESTION POOL.

**JOB CONTEXT:**
- **Position:** ${jobTitle}
- **Experience Level:** ${experienceLevel}
- **Required Skills:** ${requiredSkills}
- **Optional Skills:** ${optionalSkills}
- **Job Description:** ${jobDescription}

**SELECTED CANDIDATES:**
${selectedCandidates.map(c => `- ${c.name}: ${c.experienceYears} years experience, Skills: ${c.skills.slice(0, 3).join(', ')}, Match: ${c.matchScore}%`).join('\n')}

**ASSESSMENT FOCUS AREAS:**
${focusAreas.join(', ')}

**⭐ QUESTION POOL REQUIREMENTS:**
- **Total Pool Size:** ${questionPoolSize} questions
- **Per Candidate:** ${questionsPerCandidate} questions (randomly selected from pool)
- **Question Types:** Multiple choice (4 options each)
- **Difficulty:** Adjust based on ${experienceLevel} experience level
- **Include Coding:** ${includeCoding ? 'Yes - include programming logic questions' : 'No - focus on conceptual questions'}
- **Technology Focus:** ${focusOnTechStack ? 'Yes - emphasize specific technologies' : 'No - general technical knowledge'}

**QUESTION DISTRIBUTION FOR ${questionPoolSize} QUESTIONS:**
Create questions across these categories:

1. **Technical Skills (40%):** ${Math.round(questionPoolSize * 0.4)} questions
   - Programming concepts and ${requiredSkills}
   - Optional skills like ${optionalSkills} (when applicable)
   - Technology-specific knowledge

2. **Problem Solving (30%):** ${Math.round(questionPoolSize * 0.3)} questions
   - Logical reasoning and algorithms
   - System design concepts
   - Troubleshooting scenarios

3. **Domain Knowledge (20%):** ${Math.round(questionPoolSize * 0.2)} questions
   - Industry-specific knowledge for ${jobTitle}
   - Tools and frameworks
   - Current trends and practices

4. **Analytical Thinking (10%):** ${Math.round(questionPoolSize * 0.1)} questions
   - Data interpretation
   - Decision-making scenarios
   - Critical thinking

**OUTPUT FORMAT:**
Return a JSON object with this exact structure:

{
  "assessmentMetadata": {
    "jobTitle": "${jobTitle}",
    "targetExperience": "${experienceLevel}",
    "requiredSkills": "${requiredSkills}",
    "optionalSkills": "${optionalSkills}",
    "questionPoolSize": ${questionPoolSize},
    "questionsPerCandidate": ${questionsPerCandidate},
    "estimatedDuration": "${Math.round(questionsPerCandidate * 1.5)} minutes",
    "difficulty": "intermediate",
    "focusAreas": ${JSON.stringify(focusAreas)},
    "generatedAt": "${new Date().toISOString()}"
  },
  "questions": [
    {
      "id": 1,
      "category": "Technical Skills",
      "difficulty": "medium",
      "question": "What is the primary purpose of...",
      "options": {
        "A": "Option A text",
        "B": "Option B text", 
        "C": "Option C text",
        "D": "Option D text"
      },
      "correctAnswer": "A",
      "explanation": "Detailed explanation of why A is correct",
      "skillsTested": ["JavaScript", "Problem Solving"],
      "timeLimit": 90
    }
  ]
}

**QUALITY REQUIREMENTS:**
- Questions must be relevant to ${jobTitle} role specifically
- Focus on ${requiredSkills} as primary testing criteria
- Include ${optionalSkills} questions for comprehensive assessment
- Avoid questions that are too basic or too advanced for ${experienceLevel}
- Include practical, real-world scenarios
- Ensure each question has one clearly correct answer
- Make distractor options plausible but incorrect
- Add detailed explanations for learning purposes
- Test skills mentioned in: ${requiredSkills} and ${optionalSkills}
- CREATE VARIETY: Ensure questions are diverse enough that random selections create fair assessments

**ANTI-CHEATING CONSIDERATIONS:**
- Questions should require understanding, not just memorization
- Avoid questions easily answerable by search engines
- Include scenario-based questions requiring experience
- Make options specific enough to prevent guessing
- With ${questionPoolSize} questions, each candidate gets different subset

Generate exactly ${questionPoolSize} high-quality questions following this specification.`;
};

// Create the AI prompt
const mcqPrompt = generateMCQPrompt();

// Generate screening links for each candidate
const screeningLinks = selectedCandidates.map(candidate => ({
  candidateId: candidate.screeningId,
  candidateName: candidate.name,
  candidateEmail: candidate.email,

  // Generate unique screening URL (this would be your assessment platform URL)
  screeningUrl: `http://127.0.0.1:5500/assessment_html_page.html?id=${candidate.screeningId}`,

  // Backup/direct link format
  directLink: `https://your-domain.com/assessment?id=${candidate.screeningId}&token=${Buffer.from(candidate.email + candidate.screeningId).toString('base64')}`,

  // Link metadata
  expiresAt: candidate.linkExpiration,
  generatedAt: new Date().toISOString(),
  isActive: true
}));

// Prepare email data for each candidate with survey questions
const emailTasks = selectedCandidates.map((candidate, index) => {
  const screeningLink = screeningLinks[index];

  // ✅ Generate survey questions section for email with expected answers
  let surveyQuestionsHtml = '';
  if (surveyQuestions.length > 0) {
    const qualifyingQuestions = surveyQuestions.filter(q => q.isQualifying);
    const informationalQuestions = surveyQuestions.filter(q => !q.isQualifying);

    surveyQuestionsHtml = `
      <div style="background: #f0f8ff; border: 2px solid #007bff; border-radius: 8px; padding: 20px; margin-bottom: 20px;">
        <h3 style="margin: 0 0 15px 0; color: #0066cc;">📋 Two-Stage Assessment Process</h3>
        <p style="margin: 0 0 10px 0; color: #495057;"><strong>Stage 1: Preference Screening</strong></p>
        <p style="margin: 0 0 15px 0; color: #495057;">You must answer these qualifying questions correctly to proceed to the technical round:</p>`;

    if (qualifyingQuestions.length > 0) {
      surveyQuestionsHtml += `<ul style="margin: 0 0 15px 0; padding-left: 20px; color: #495057;">`;
      qualifyingQuestions.forEach(q => {
        let optionText = '';
        if (q.fieldOptions && q.fieldOptions.values) {
          optionText = ` (${q.fieldOptions.values.map(opt => opt.option).join(' / ')})`;
        }
        surveyQuestionsHtml += `<li><strong>✅ ${q.fieldLabel}</strong>${optionText} - <em>Qualifying Question</em></li>`;
      });
      surveyQuestionsHtml += `</ul>`;
    }

    if (informationalQuestions.length > 0) {
      surveyQuestionsHtml += `<p style="margin: 15px 0 10px 0; color: #495057;"><strong>Additional Information Questions:</strong></p>`;
      surveyQuestionsHtml += `<ul style="margin: 0 0 15px 0; padding-left: 20px; color: #495057;">`;
      informationalQuestions.forEach(q => {
        let optionText = '';
        if (q.fieldOptions && q.fieldOptions.values) {
          optionText = ` (${q.fieldOptions.values.map(opt => opt.option).join(' / ')})`;
        }
        surveyQuestionsHtml += `<li><strong>ℹ️ ${q.fieldLabel}</strong>${optionText} - <em>For our reference only</em></li>`;
      });
      surveyQuestionsHtml += `</ul>`;
    }

    surveyQuestionsHtml += `
        <p style="margin: 10px 0 0 0; font-size: 12px; color: #6c757d; font-style: italic;">
          <strong>Important:</strong> You must pass the preference screening to access the technical assessment.
        </p>
      </div>`;
  }

  return {
    to: candidate.email,
    candidateName: candidate.name,
    subject: `Two-Stage Assessment Invitation - ${jobRequirements.title} Position`,

