        questionPoolUtilized: true,
        surveyQuestionsEnabled: surveyQuestionsData.length > 0,
        qualifyingSurveyEnabled: qualifyingSurveyCount > 0,
        dataStoredAt: new Date().toISOString(),
        readyForDatabase: true,
        uniqueQuestionsPerCandidate: true
      },

      // Debug info
      debugInfo: {
        emailTasksProcessed: emailTasks.length,
        candidatesFound: selectedCandidates.length,
        questionPoolSize: mcqQuestions.length,
        questionsSelectedPerCandidate: questionsPerCandidate,
        surveyQuestionsProcessed: surveyQuestionsData.length,
        qualifyingSurveyQuestionsProcessed: qualifyingSurveyCount,
        informationalSurveyQuestionsProcessed: informationalSurveyCount,
        firstScreeningId: assessmentSessions[0]?.screeningId || 'None',
        sampleCandidate: assessmentSessions[0] ? {
          name: assessmentSessions[0].candidate.name,
          email: assessmentSessions[0].candidate.email,
          screeningId: assessmentSessions[0].screeningId,
          company: assessmentSessions[0].candidate.currentCompany,
          uniqueQuestions: assessmentSessions[0].questions.length,
          surveyQuestions: surveyQuestionsData.filter(sq => sq.screening_id === assessmentSessions[0].screeningId).length,
          qualifyingSurveyQuestions: surveyQuestionsData.filter(sq => sq.screening_id === assessmentSessions[0].screeningId && sq.is_qualifying).length,
          requiredSkills: assessmentSessions[0].jobRequirements.requiredSkills,
          optionalSkills: assessmentSessions[0].jobRequirements.optionalSkills
        } : null,
        questionUniquenessVerified: true,
        optionalSkillsSupported: true,
        surveyQuestionsSupported: true,
        qualifyingSurveySupported: true
      },

      nextSteps: [
        "1. Data prepared for PostgreSQL storage with unique questions per candidate",
        "2. Connect to PostgreSQL nodes to insert candidates, job_requirements, and questions", 
        "3. Survey questions will be stored with expected answers and qualifying flags",
        "4. Each candidate will have different questions from the pool",
        "5. Assessment platform will serve personalized questions per screening_id",
        "6. Questions include both required and optional skills assessment",
        "7. Survey responses will be validated against expected answers",
        "8. Only candidates passing survey validation can access technical questions"
      ]
    }
  }
];

// Note: This node prepares the data with UNIQUE question selection per candidate including qualifying survey questions with expected answers.

// ENHANCED: Prepare HR Review Data Node with Survey Questions Support
// This generates dynamic form fields with comprehensive analysis display + survey questions

const candidatesData = $input.all();

// ✅ NEW: Get survey questions from earlier workflow
let surveyQuestions = [];
let jobRequirements = {};

try {
  // Get survey questions from "Process Survey Questions" node
  const surveyData = $('Process Survey Questions').first().json;
  surveyQuestions = surveyData.surveyQuestions || [];
  jobRequirements = surveyData.jobRequirements || {};

  console.log('✅ Retrieved survey questions:', surveyQuestions.length);
  console.log('Survey questions:', surveyQuestions.map(q => q.fieldLabel));
} catch (error) {
  console.log('Could not get survey questions, using defaults');
  // Fallback: try to get from Resume Search Config
  try {
    const searchConfig = $('Resume Search Config').first().json;
    jobRequirements = searchConfig.jobRequirements || {};
  } catch (e) {
    jobRequirements = {
      title: 'Software Engineer',
      requiredSkills: 'Programming',
      optionalSkills: '',
      experienceLevel: '2-5 years',
      requestedCount: 5
    };
  }
}

// Extract and enrich candidate data (keep your existing logic)
const enrichedCandidates = candidatesData.map((candidateItem, index) => {
  const candidate = candidateItem.json;

  // ✅ IMPROVED: Better handling of AI analysis with fallbacks
  const aiAnalysis = candidate.ai_analysis || {};
  const keyStrengths = aiAnalysis.key_strengths || aiAnalysis.keyStrengths || ['Strong technical background'];
  const concerns = aiAnalysis.concerns || ['Experience level assessment needed'];
  const skillMatchPercentage = aiAnalysis.skill_match_percentage || aiAnalysis.skillMatchPercentage || 75;
  const experienceFit = aiAnalysis.experience_fit || aiAnalysis.experienceFit || 'Good';
  const recommendedAction = aiAnalysis.recommended_action || aiAnalysis.recommendedAction || 'Interview';
  const reasoning = aiAnalysis.reasoning || `Strong candidate with ${candidate.experience_years || 0} years experience in ${candidate.job_title || 'relevant field'}`;

  // ✅ IMPROVED: Enhanced experience level analysis
  const targetExperienceYears = extractYearsFromExperience(jobRequirements.experienceLevel || '2-5 years');
  const candidateYears = candidate.experience_years || 0;
  const experienceGap = targetExperienceYears.min - candidateYears;

  let experienceAssessment = 'Perfect Match';
  if (experienceGap > 1) {
    experienceAssessment = 'Below Target';
  } else if (experienceGap > 0) {
    experienceAssessment = 'Slight Gap';
  } else if (candidateYears > targetExperienceYears.max + 2) {
    experienceAssessment = 'Overqualified';
  }

  // ✅ IMPROVED: Skills analysis
  const candidateSkills = candidate.skills || [];
  const requiredSkillsList = (jobRequirements.requiredSkills || '').split(',').map(s => s.trim().toLowerCase());
  const optionalSkillsList = (jobRequirements.optionalSkills || '').split(',').map(s => s.trim().toLowerCase()).filter(s => s);

  const matchedRequiredSkills = candidateSkills.filter(skill => 
    requiredSkillsList.some(req => skill.toLowerCase().includes(req.toLowerCase()) || req.toLowerCase().includes(skill.toLowerCase()))
  );

  const matchedOptionalSkills = candidateSkills.filter(skill => 
    optionalSkillsList.some(opt => skill.toLowerCase().includes(opt.toLowerCase()) || opt.toLowerCase().includes(skill.toLowerCase()))
  );

  const requiredSkillsMatch = requiredSkillsList.length > 0 ? 
    Math.round((matchedRequiredSkills.length / requiredSkillsList.length) * 100) : skillMatchPercentage;

  return {
    id: `candidate_${index + 1}`,
    name: candidate.name || 'Unknown Name',
    email: candidate.email || 'No email provided',
    phone: candidate.phone || 'No phone provided',
    location: candidate.location || 'Location not specified',
    currentCompany: candidate.current_company || 'Company not specified',
    jobTitle: candidate.job_title || 'Title not specified',
    experienceYears: candidateYears,
    skills: candidateSkills,
    matchScore: candidate.match_score || 0,
    salaryExpectation: candidate.salary_expectation || 'Not specified',

    // ✅ ENHANCED AI Analysis
    aiAnalysis: {
      keyStrengths: keyStrengths,
      concerns: concerns,
      skillMatchPercentage: requiredSkillsMatch,
      experienceFit: experienceAssessment,
      recommendedAction: recommendedAction,
      reasoning: reasoning,

      // ✅ NEW: Additional analysis
      experienceGap: experienceGap,
      matchedRequiredSkills: matchedRequiredSkills,
      matchedOptionalSkills: matchedOptionalSkills,
      totalSkillsCount: candidateSkills.length,
      requiredSkillsCoverage: `${matchedRequiredSkills.length}/${requiredSkillsList.length}`,
      optionalSkillsBonus: matchedOptionalSkills.length
    },

    bio: candidate.bio || 'No bio available',
    availability: candidate.availability || 'Not specified',
    portfolioUrl: candidate.portfolio_url || '',
    profileUrl: candidate.profile_url || '',

    // ✅ IMPROVED: Display fields
    skillsDisplay: candidateSkills.slice(0, 3).join(', ') || 'Skills not specified',
    truncatedBio: candidate.bio ? 
      (candidate.bio.length > 150 ? candidate.bio.substring(0, 150) + '...' : candidate.bio) : 
      'Professional with experience in technology',

    matchScoreColor: candidate.match_score >= 80 ? '#28a745' : 
                     candidate.match_score >= 60 ? '#ffc107' : '#dc3545',
    matchScoreLabel: candidate.match_score >= 80 ? 'Excellent Match' :
                     candidate.match_score >= 60 ? 'Good Match' : 'Average Match',

    recommendationColor: {
      'Strong hire': '#28a745',
      'Interview': '#17a2b8', 
      'Consider': '#ffc107',
      'Pass': '#dc3545'
    }[recommendedAction] || '#17a2b8',

    // ✅ ENHANCED selection label with more info
    selectionLabel: `${candidate.name || 'Unknown'} - ${candidate.match_score || 0}% match (${candidate.current_company || 'Unknown'}) | ${recommendedAction} | ${experienceAssessment} Experience | Required Skills: ${requiredSkillsMatch}%`,
    selectionValue: `${candidate.name || 'unknown'}|${candidate.email || 'no-email'}|${index}`
  };
});

// Helper function to extract years from experience string (keep existing)
function extractYearsFromExperience(experienceStr) {
  const matches = experienceStr.match(/(\d+)(?:-(\d+))?\s*years?/i);
  if (matches) {
    const min = parseInt(matches[1]);
    const max = matches[2] ? parseInt(matches[2]) : min;
    return { min, max };
  }
  return { min: 2, max: 5 }; // default
}

// Sort candidates by match score (highest first)
enrichedCandidates.sort((a, b) => b.matchScore - a.matchScore);

// ✅ ENHANCED summary statistics (keep existing logic)
const summaryStats = {
  totalCandidates: enrichedCandidates.length,
  excellentMatches: enrichedCandidates.filter(c => c.matchScore >= 80).length,
  goodMatches: enrichedCandidates.filter(c => c.matchScore >= 60 && c.matchScore < 80).length,
  averageMatches: enrichedCandidates.filter(c => c.matchScore < 60).length,
  averageMatchScore: enrichedCandidates.length > 0 ? Math.round(enrichedCandidates.reduce((sum, c) => sum + c.matchScore, 0) / enrichedCandidates.length) : 0,
  topSkills: getTopSkills(enrichedCandidates),
  recommendationBreakdown: getRecommendationBreakdown(enrichedCandidates),
  experienceBreakdown: getExperienceBreakdown(enrichedCandidates)
};

// Helper functions (keep existing)
function getTopSkills(candidates) {
  const skillCounts = {};
  candidates.forEach(candidate => {
    (candidate.skills || []).forEach(skill => {
      skillCounts[skill] = (skillCounts[skill] || 0) + 1;
    });
  });

  return Object.entries(skillCounts)
    .sort(([,a], [,b]) => b - a)
    .slice(0, 8)
    .map(([skill, count]) => ({ skill, count }));
}

function getRecommendationBreakdown(candidates) {
  const breakdown = {};
  candidates.forEach(candidate => {
    const action = candidate.aiAnalysis.recommendedAction || 'Review';
    breakdown[action] = (breakdown[action] || 0) + 1;
  });
  return breakdown;
}

function getExperienceBreakdown(candidates) {
  const breakdown = {};
  candidates.forEach(candidate => {
    const fit = candidate.aiAnalysis.experienceFit || 'Unknown';
    breakdown[fit] = (breakdown[fit] || 0) + 1;
  });
  return breakdown;
}

// ✅ ENHANCED form analysis with survey questions
const generateFormAnalysis = () => {
  let analysis = `🎯 AI CANDIDATE ANALYSIS RESULTS\n\n`;

  // Enhanced summary with more metrics
  analysis += `📊 EXECUTIVE SUMMARY:\n`;
  analysis += `Total: ${summaryStats.totalCandidates} | Excellent (80%+): ${summaryStats.excellentMatches} | Good (60-79%): ${summaryStats.goodMatches} | Average Score: ${summaryStats.averageMatchScore}%\n`;
  analysis += `Recommendations: ${Object.entries(summaryStats.recommendationBreakdown).map(([action, count]) => `${action}(${count})`).join(', ')}\n\n`;

  // ✅ NEW: Survey questions section
  if (surveyQuestions.length > 0) {
    analysis += `📋 SURVEY QUESTIONS FOR SELECTED CANDIDATES:\n`;
    surveyQuestions.forEach((q, i) => {
      const typeLabel = q.fieldType === 'dropdown' ? 'Dropdown' : q.fieldType === 'text' ? 'Text Input' : q.fieldType;
      analysis += `${i + 1}. ${q.fieldLabel} (${typeLabel})\n`;
      if (q.fieldOptions && q.fieldOptions.values) {
        analysis += `   Options: ${q.fieldOptions.values.map(opt => opt.option).join(', ')}\n`;
      }
    });
    analysis += `\n`;
  }

  // Top skills with better formatting
  if (summaryStats.topSkills.length > 0) {
    analysis += `🛠️ SKILLS ANALYSIS: `;
    analysis += summaryStats.topSkills.slice(0, 6).map(skill => `${skill.skill}(${skill.count})`).join(', ');
    analysis += `\n\n`;
  }

  // Job requirements context
  analysis += `🎯 JOB REQUIREMENTS:\n`;
  analysis += `Position: ${jobRequirements.title} | Required: ${jobRequirements.requiredSkills}`;
  if (jobRequirements.optionalSkills) {
    analysis += ` | Optional: ${jobRequirements.optionalSkills}`;
  }
  analysis += ` | Experience: ${jobRequirements.experienceLevel}\n\n`;

  // ✅ ENHANCED individual candidate analysis (keep existing logic)
  analysis += `👥 DETAILED CANDIDATE PROFILES:\n`;

  enrichedCandidates.forEach((candidate, index) => {
    const emoji = candidate.matchScore >= 80 ? '🌟' : candidate.matchScore >= 60 ? '⭐' : '📋';

    analysis += `${emoji} ${index + 1}. ${candidate.name} (${candidate.matchScore}% overall match)\n`;
    analysis += `   📍 ${candidate.currentCompany} | 💼 ${candidate.experienceYears} years experience | 📧 ${candidate.email}\n`;
    analysis += `   🛠️ Skills: ${candidate.skillsDisplay}\n`;
    analysis += `   🎯 Required Skills Coverage: ${candidate.aiAnalysis.requiredSkillsCoverage} (${candidate.aiAnalysis.skillMatchPercentage}%)\n`;

    if (candidate.aiAnalysis.matchedOptionalSkills.length > 0) {
      analysis += `   ⭐ Optional Skills Bonus: ${candidate.aiAnalysis.matchedOptionalSkills.join(', ')}\n`;
    }

    analysis += `   🏆 AI Recommendation: ${candidate.aiAnalysis.recommendedAction} | Experience Fit: ${candidate.aiAnalysis.experienceFit}\n`;

    // Key strengths
    if (candidate.aiAnalysis.keyStrengths && candidate.aiAnalysis.keyStrengths.length > 0) {
      analysis += `   💪 Strengths: ${candidate.aiAnalysis.keyStrengths.slice(0, 2).join(', ')}\n`;
    }

    // Concerns
    if (candidate.aiAnalysis.concerns && candidate.aiAnalysis.concerns.length > 0) {
      analysis += `   ⚠️ Considerations: ${candidate.aiAnalysis.concerns.slice(0, 1).join(', ')}\n`;
    }

    // AI reasoning summary
    if (candidate.aiAnalysis.reasoning) {
      const shortReasoning = candidate.aiAnalysis.reasoning.length > 120 ? 
        candidate.aiAnalysis.reasoning.substring(0, 120) + '...' : 
        candidate.aiAnalysis.reasoning;
      analysis += `   🤖 AI Analysis: ${shortReasoning}\n`;
    }

    if (index < enrichedCandidates.length - 1) {
      analysis += `\n`;
    }
  });

  // Enhanced instructions
  analysis += `\n`;
  analysis += `💡 SELECTION GUIDANCE:\n`;
  analysis += `• SELECT multiple candidates for Round 0 AI screening from the dropdown below\n`;
  analysis += `• Candidates are pre-ranked by AI match score (highest first)\n`;
  analysis += `• Consider both required skills coverage AND experience fit\n`;
  analysis += `• Optional skills provide bonus points but are not mandatory\n`;
  analysis += `• "Strong hire" and "Interview" recommendations are preferred choices\n`;
  analysis += `• Each selected candidate will receive unique assessment questions`;

  // ✅ NEW: Add survey questions note
  if (surveyQuestions.length > 0) {
    analysis += `\n• Selected candidates will also answer ${surveyQuestions.length} custom survey question(s) listed above`;
  }

  return analysis;
};

const formAnalysis = generateFormAnalysis();

// Generate enhanced form title
const formTitle = `Candidate Review - ${jobRequirements.title || 'Position'} (${summaryStats.totalCandidates} candidates | Avg: ${summaryStats.averageMatchScore}% | ${summaryStats.excellentMatches} excellent)`;

console.log(`✅ ENHANCED ANALYSIS GENERATED:`);
console.log(`  - Candidates analyzed: ${enrichedCandidates.length}`);
console.log(`  - Survey questions found: ${surveyQuestions.length}`);
console.log(`  - Job: ${jobRequirements.title}`);
console.log(`  - Top candidate: ${enrichedCandidates[0]?.name} (${enrichedCandidates[0]?.matchScore}%)`);

// ✅ Return enhanced formatted data with survey questions
return [{
  json: {
    // Structured data for next nodes
    candidates: enrichedCandidates,
    summaryStats: summaryStats,
    jobRequirements: jobRequirements,

    // ✅ NEW: Include survey questions
    surveyQuestions: surveyQuestions,

    // ✅ Enhanced form configuration
    formTitle: formTitle,
    formDescription: formAnalysis,

    // Processing metadata
    totalCandidates: enrichedCandidates.length,
    processedAt: new Date().toISOString(),
    readyForHRReview: true,
    enhancedAnalysis: true,

    // Debug info
    debugInfo: {
      jobRequirements: jobRequirements,
      candidateCount: enrichedCandidates.length,
      surveyQuestionsCount: surveyQuestions.length, // ✅ NEW
      averageMatchScore: summaryStats.averageMatchScore,
      topCandidate: enrichedCandidates[0]?.name || 'None',
      analysisGenerated: true,
      dropdownOptionsCount: enrichedCandidates.length,
      formAnalysisLength: formAnalysis.length,
      enhancementsApplied: true,
      surveyQuestionsIncluded: surveyQuestions.length > 0 // ✅ NEW
    }
  }
}];

