// Helper function to calculate progress percentage
function calculateProgress(statusUpdate, surveyStatus, technicalUnlocked) {
  let percentage = 0;
  let currentStage = 'Not Started';
  let nextStep = 'Begin assessment';

  switch (statusUpdate) {
    case 'assessment_started':
    case 'survey_in_progress':
      percentage = 10;
      currentStage = 'Survey In Progress';
      nextStep = 'Complete preference questions';
      break;
    case 'survey_completed':
    case 'survey_validation_pending':
      percentage = 30;
      currentStage = 'Survey Validation Pending';
      nextStep = 'Await validation results';
      break;
    case 'survey_validation_passed':
    case 'technical_unlocked':
      percentage = 50;
      currentStage = 'Technical Assessment Unlocked';
      nextStep = 'Begin technical questions';
      break;
    case 'technical_started':
    case 'technical_in_progress':
      percentage = 75;
      currentStage = 'Technical Assessment In Progress';
      nextStep = 'Complete technical questions';
      break;
    case 'technical_completed':
    case 'assessment_finished':
      percentage = 100;
      currentStage = 'Assessment Complete';
      nextStep = 'Await results';
      break;
    case 'survey_validation_failed':
      percentage = 40;
      currentStage = 'Assessment Ended';
      nextStep = 'Assessment concluded';
      break;
  }

  return {
    percentage: percentage,
    currentStage: currentStage,
    nextStep: nextStep,
    twoStageProcess: true,
    stage1Complete: ['survey_validation_passed', 'technical_unlocked', 'technical_started', 'technical_in_progress', 'technical_completed', 'assessment_finished'].includes(statusUpdate),
    stage2Available: technicalUnlocked || ['technical_unlocked', 'technical_started', 'technical_in_progress', 'technical_completed', 'assessment_finished'].includes(statusUpdate)
  };
}

// Helper function to determine available actions
function getAvailableActions(statusUpdate, surveyStatus, technicalUnlocked) {
  const actions = [];

  switch (statusUpdate) {
    case 'assessment_started':
      actions.push('continue_survey', 'save_progress');
      break;
    case 'survey_completed':
      actions.push('await_validation');
      break;
    case 'survey_validation_passed':
      actions.push('start_technical_assessment');
      break;
    case 'technical_started':
      actions.push('continue_technical', 'save_technical_progress');
      break;
    case 'technical_completed':
      actions.push('view_results');
      break;
    case 'survey_validation_failed':
      actions.push('view_feedback');
      break;
  }

  return actions;
}

