  console.log('⚠️ Could not get OneDrive files:', error.message);
}
// Get extracted resume text from earlier in workflow  
let extractedTexts = [];
try {
  extractedTexts = $('Extract from File').all();
  console.log(`✅ Found ${extractedTexts.length} extracted resume texts`);
} catch (error) {
  console.log('⚠️ Could not get extracted texts:', error.message);
}
// Create a mapping of candidate email to resume data
// We'll match candidates to their resumes by email or name
const resumeDataMap = {};
// First, try to get candidate info from AI processing
let aiCandidates = [];
try {
  aiCandidates = $('Code2').all();
  console.log(`✅ Found ${aiCandidates.length} AI-processed candidates`);
} catch (error) {
  console.log('⚠️ Could not get AI candidates');
}
// Build the resume mapping
aiCandidates.forEach((candidate, index) => {
  const candidateJson = candidate.json;
  const email = candidateJson.email;
  if (email && driveFiles[index] && extractedTexts[index]) {
    const driveFile = driveFiles[index].json;
    const extractedData = extractedTexts[index].json;
    resumeDataMap[email] = {
      resume_drive_id: driveFile.id || null,
      resume_file_name: driveFile.name || null,
      resume_drive_url: driveFile.webUrl || null,
      resume_text: extractedData.text || null
    };
    console.log(`  ✅ Mapped resume for: ${email}`);
    console.log(`     - Drive ID: ${driveFile.id}`);
    console.log(`     - File Name: ${driveFile.name}`);
    console.log(`     - Text Length: ${extractedData.text?.length || 0} chars`);
  }
});
console.log(`✅ Created resume mapping for ${Object.keys(resumeDataMap).length} candidates`);
// Enrich each candidate with their resume data
const enrichedCandidates = candidatesData.map(candidate => {
  const email = candidate.email;
  const resumeData = resumeDataMap[email] || {
    resume_drive_id: null,
    resume_file_name: null,
    resume_drive_url: null,
    resume_text: null
  };
  if (resumeData.resume_drive_id) {
    console.log(`  ✅ Enriched: ${candidate.name} (${email})`);
  } else {
    console.log(`  ⚠️ No resume data for: ${candidate.name} (${email})`);
  }
  return {
    ...candidate,
    ...resumeData
  };
});
console.log(`\n✅ ENRICHMENT COMPLETE:`);
console.log(`  - Total candidates: ${enrichedCandidates.length}`);
console.log(`  - With resume data: ${enrichedCandidates.filter(c => c.resume_drive_id).length}`);
console.log(`  - Missing resume data: ${enrichedCandidates.filter(c => !c.resume_drive_id).length}`);
// Return enriched data in the same format as Store Assessment Data
return [{
  json: {
    ...storeData,  // Keep all original data
    candidatesData: enrichedCandidates  // Replace with enriched candidates
  }
}];
